function base64urlToUint8Array(str){const base64=str.replace(/-/g,"+").replace(/_/g,"/");const padded=base64.padEnd(base64.length+(4-base64.length%4)%4,"=");return Uint8Array.from(atob(padded),c=>c.charCodeAt(0))}function uint8ArrayToBase64url(buffer){const bytes=buffer instanceof Uint8Array?buffer:new Uint8Array(buffer);return btoa(String.fromCharCode(...bytes)).replace(/\+/g,"-").replace(/\//g,"_").replace(/=/g,"")}function prepareRequestOptions(json){const opts=JSON.parse(JSON.stringify(json));opts.challenge=base64urlToUint8Array(json.challenge);if(opts.allowCredentials){opts.allowCredentials=opts.allowCredentials.map(c=>({...c,id:base64urlToUint8Array(c.id)}))}return opts}function serializeAssertionResponse(cred){const r={id:cred.id,rawId:uint8ArrayToBase64url(new Uint8Array(cred.rawId)),type:cred.type,response:{clientDataJSON:uint8ArrayToBase64url(new Uint8Array(cred.response.clientDataJSON)),authenticatorData:uint8ArrayToBase64url(new Uint8Array(cred.response.authenticatorData)),signature:uint8ArrayToBase64url(new Uint8Array(cred.response.signature))}};if(cred.response.userHandle){r.response.userHandle=uint8ArrayToBase64url(new Uint8Array(cred.response.userHandle))}return r}async function authenticateWithPasskey(){const optRes=await fetch(window.__PASSKEY_OPTIONS_URL__,{method:"POST",headers:{"Content-Type":"application/json"},body:"{}"});const optData=await optRes.json();if(!optRes.ok)throw new Error(optData.error||"Errore nel recupero delle opzioni passkey.");const{success:_s,...optionsJson}=optData;let credential;try{credential=await navigator.credentials.get({publicKey:prepareRequestOptions(optionsJson)})}catch(e){throw new Error("Autenticazione annullata: "+e.message)}if(!credential)throw new Error("Nessuna credenziale ottenuta dal browser.");const verRes=await fetch(window.__PASSKEY_VERIFY_URL__,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(serializeAssertionResponse(credential))});const result=await verRes.json();if(!verRes.ok)throw new Error(result.error||"Verifica passkey fallita.");return result.redirect}document.addEventListener("DOMContentLoaded",()=>{const btn=document.getElementById("passkey-auth-btn");if(!btn)return;btn.addEventListener("click",async()=>{const statusEl=document.getElementById("passkey-auth-status");btn.disabled=true;if(statusEl)statusEl.textContent="Autenticazione in corso…";try{const redirect=await authenticateWithPasskey();window.location.href=redirect}catch(e){if(statusEl){statusEl.textContent=e.message;statusEl.style.color="#842029"}btn.disabled=false}})});